function drawPlayField() {
    // Sort cards by layer for proper rendering
    const sortedCards = [...cards].sort((a, b) => a.layer - b.layer);

    for (let card of sortedCards) {
        if (card.removed || card.animating) continue;

        const clickable = isCardClickable(card);
        const isHover = hoverCard && hoverCard.id === card.id && clickable;

        drawCard(card, card.x, card.y, CARD_W, CARD_H, isHover);
    }
}

function drawParticles() {
    for (let p of particles) {
        ctx.save();
        ctx.globalAlpha = p.life;
        ctx.fillStyle = p.color;

        if (p.type === 'star') {
            drawStar(p.x, p.y, p.size);
        } else if (p.type === 'confetti') {
            ctx.fillRect(p.x - p.size / 2, p.y - p.size / 2, p.size, p.size * 0.6);
        } else {
            ctx.beginPath();
            ctx.arc(p.x, p.y, p.size, 0, Math.PI * 2);
            ctx.fill();
        }

        ctx.restore();
    }
}

function drawStar(x, y, size) {
    ctx.beginPath();
    for (let i = 0; i < 5; i++) {
        const angle = (i * 4 * Math.PI / 5) - Math.PI / 2;
        const px = x + Math.cos(angle) * size;
        const py = y + Math.sin(angle) * size;
        if (i === 0) ctx.moveTo(px, py);
        else ctx.lineTo(px, py);
    }
    ctx.closePath();
    ctx.fill();
}

function drawMessage() {
    if (messageTimer <= 0) return;

    const alpha = Math.min(1, messageTimer / 30);
    ctx.save();
    ctx.globalAlpha = alpha;

    ctx.fillStyle = 'rgba(0,0,0,0.7)';
    const textW = ctx.measureText(messageText).width + 40;
    roundRect(180 - textW / 2, 75, textW, 35, 10, true, false);

    ctx.fillStyle = '#FFD700';
    ctx.font = 'bold 16px Arial';
    ctx.textAlign = 'center';
    ctx.textBaseline = 'middle';
    ctx.fillText(messageText, 180, 92);

    ctx.restore();
}

function roundRect(x, y, w, h, r, fill, stroke) {
    ctx.beginPath();
    ctx.moveTo(x + r, y);
    ctx.lineTo(x + w - r, y);
    ctx.quadraticCurveTo(x + w, y, x + w, y + r);
    ctx.lineTo(x + w, y + h - r);
    ctx.quadraticCurveTo(x + w, y + h, x + w - r, y + h);
    ctx.lineTo(x + r, y + h);
    ctx.quadraticCurveTo(x, y + h, x, y + h - r);
    ctx.lineTo(x, y + r);
    ctx.quadraticCurveTo(x, y, x + r, y);
    ctx.closePath();
    if (fill) ctx.fill();
    if (stroke) ctx.stroke();
}

// Update functions
function update() {
    // Update animations
    for (let i = animatingCards.length - 1; i >= 0; i--) {
        const card = animatingCards[i];
        card.animProgress += 0.08;

        if (card.animProgress >= 1) {
            card.animProgress = 1;
            card.animating = false;
            card.x = card.animTargetX;
            card.y = card.animTargetY;
            animatingCards.splice(i, 1);

            // Check for matches after animation completes
            if (animatingCards.length === 0) {
                setTimeout(checkMatch, 100);
            }
        } else {
            // Ease out cubic
            const t = 1 - Math.pow(1 - card.animProgress, 3);
            card.x = card.animStartX + (card.animTargetX - card.animStartX) * t;
            card.y = card.animStartY + (card.animTargetY - card.animStartY) * t;
        }
    }

    // Update particles
    for (let i = particles.length - 1; i >= 0; i--) {
        const p = particles[i];
        p.x += p.vx;
        p.y += p.vy;
        p.vy += 0.05; // gravity
        p.life -= p.decay;

        if (p.life <= 0) {
            particles.splice(i, 1);
        }
    }

    // Update timers
    if (messageTimer > 0) messageTimer--;
    if (comboTimer > 0) comboTimer--;
    if (shakeTimer > 0) shakeTimer--;

    // Update slot card positions (smooth repositioning)
    for (let i = 0; i < slotCards.length; i++) {
        const card = slotCards[i];
        if (!card.animating) {
            const target = getSlotPosition(i);
            card.x += (target.x - card.x) * 0.3;
            card.y += (target.y - card.y) * 0.3;
        }
    }
}

function render() {
    ctx.clearRect(0, 0, 360, 640);

    if (gameState === 'menu') {
        drawMenu();
    } else if (gameState === 'playing') {
        drawBackground();

        // Shake effect
        if (shakeTimer > 0) {
            ctx.save();
            ctx.translate(
                Math.sin(shakeTimer * 1.5) * 3,
                Math.cos(shakeTimer * 2) * 2
            );
        }

        drawPlayField();
        drawSlotArea();

        if (shakeTimer > 0) ctx.restore();

        drawItems();
        drawHUD();
        drawParticles();
        drawMessage();

        // Draw animating cards on top
        for (let card of animatingCards) {
            drawCard(card, card.x, card.y, CARD_W, CARD_H, true);
        }
    } else if (gameState === 'win') {
        drawWinScreen();
        drawParticles();
    } else if (gameState === 'lose') {
        drawLoseScreen();
    }
}

function gameLoop() {
    update();
    render();
    requestAnimationFrame(gameLoop);
}

// Input handling
function getCardAt(mx, my) {
    // Check from top layer down
    const sortedCards = [...cards].sort((a, b) => b.layer - a.layer);
    for (let card of sortedCards) {
        if (card.removed) continue;
        if (mx >= card.x && mx <= card.x + CARD_W &&
            my >= card.y && my <= card.y + CARD_H) {
            return card;
        }
    }
    return null;
}

canvas.addEventListener('mousemove', (e) => {
    const rect = canvas.getBoundingClientRect();
    const scaleX = canvas.width / rect.width;
    const scaleY = canvas.height / rect.height;
    const mx = (e.clientX - rect.left) * scaleX;
    const my = (e.clientY - rect.top) * scaleY;

    if (gameState === 'playing') {
        hoverCard = getCardAt(mx, my);
    }
});

canvas.addEventListener('click', (e) => {
    const rect = canvas.getBoundingClientRect();
    const scaleX = canvas.width / rect.width;
    const scaleY = canvas.height / rect.height;
    const mx = (e.clientX - rect.left) * scaleX;
    const my = (e.clientY - rect.top) * scaleY;

    handleClick(mx, my);
});

canvas.addEventListener('touchstart', (e) => {
    e.preventDefault();
    const rect = canvas.getBoundingClientRect();
    const scaleX = canvas.width / rect.width;
    const scaleY = canvas.height / rect.height;
    const touch = e.touches[0];
    const mx = (touch.clientX - rect.left) * scaleX;
    const my = (touch.clientY - rect.top) * scaleY;

    handleClick(mx, my);
}, { passive: false });

function handleClick(mx, my) {
    if (gameState === 'menu') {
        // Level 1 button
        if (mx >= 80 && mx <= 280 && my >= 230 && my <= 280) {
            currentLevel = 1;
            generateLevel(1);
            gameState = 'playing';
        }
        // Level 2 button
        if (mx >= 80 && mx <= 280 && my >= 300 && my <= 350) {
            currentLevel = 2;
            generateLevel(2);
            gameState = 'playing';
        }
        return;
    }

    if (gameState === 'win') {
        // Next level button (level 1 only)
        if (currentLevel === 1 && mx >= 80 && mx <= 280 && my >= 340 && my <= 385) {
            currentLevel = 2;
            generateLevel(2);
            gameState = 'playing';
        }
        // Menu button
        if (mx >= 80 && mx <= 280 && my >= 395 && my <= 435) {
            gameState = 'menu';
        }
        return;
    }

    if (gameState === 'lose') {
        // Revive button
        if (!usedItems.revive && mx >= 80 && mx <= 280 && my >= 300 && my <= 345) {
            useRevive();
        }
        // Restart button
        if (mx >= 80 && mx <= 280 && my >= 355 && my <= 395) {
            generateLevel(currentLevel);
            gameState = 'playing';
        }
        // Menu button
        if (mx >= 80 && mx <= 280 && my >= 400 && my <= 440) {
            gameState = 'menu';
        }
        return;
    }

    if (gameState === 'playing') {
        // Check item buttons
        const itemY = 600;
        const itemW = 70;
        const startX = (360 - 3 * itemW) / 2;

        for (let i = 0; i < 3; i++) {
            const x = startX + i * itemW + 5;
            if (mx >= x && mx <= x + itemW - 10 && my >= itemY && my <= itemY + 32) {
                if (i === 0) useRemove3();
                else if (i === 1) useUndo();
                else if (i === 2) useShuffle();
                return;
            }
        }

        // Check card clicks
        if (animatingCards.length > 0) return; // Wait for animations

        const card = getCardAt(mx, my);
        if (card && isCardClickable(card)) {
            createClickParticles(mx, my);

            if (slotCards.length < MAX_SLOTS) {
                addToSlot(card);
            } else {
                shakeTimer = 20;
                showMessage('卡槽已满！');
            }
        } else if (card && !card.removed) {
            shakeTimer = 10;
        }
    }
}

// Initialize and start
gameLoop();
</script>
